static void stopwatch_start_local(stopwatch *sw){
    if (sw == NULL) return;
    bzero(&sw->begin, sizeof(struct timeval));
    bzero(&sw->end  , sizeof(struct timeval));
    gettimeofday(&sw->begin, NULL);
}

static void stopwatch_stop_local(stopwatch *sw){
    if (sw == NULL) return;
    gettimeofday(&sw->end, NULL);
}

static double get_interval_by_sec_local(stopwatch *sw){
    if (sw == NULL) return 0;
    return ((double)(sw->end.tv_sec-sw->begin.tv_sec)+(double)(sw->end.tv_usec-sw->begin.tv_usec)/1000000);
}

static int get_interval_by_usec_local(stopwatch *sw){
    if (sw == NULL) return 0;
    return ((sw->end.tv_sec-sw->begin.tv_sec)*1000000+(sw->end.tv_usec-sw->begin.tv_usec));
}

static func_ret_t create_matrix_from_file_local(float **mp, const char* filename, int *size_p){
  int i, j, size;
  float *m;
  FILE *fp = NULL;

  fp = fopen(filename, "rb");
  if ( NULL == fp) {
      return RET_FAILURE;
  }

  fscanf(fp, "%d\n", &size);

  m = (float*) malloc(sizeof(float)*size*size);
  if ( NULL == m) {
      fclose(fp);
      return RET_FAILURE;
  }

  for (i=0; size > i; i++) {
      for (j=0; size > j; j++) {
          fscanf(fp, "%f ", m+i*size+j);
      }
  }

  fclose(fp);

  *size_p = size;
  *mp = m;

  return RET_SUCCESS;
}

