static func_ret_t lud_verify_local(float *m, float *lu, int matrix_dim){
  int i,j,k;
  float *tmp = (float*)malloc(matrix_dim*matrix_dim*sizeof(float));

  for (i=0; matrix_dim > i; i ++)
    for (j=0; matrix_dim > j; j++) {
        float sum = 0;
        float l,u;
        for (k=0; MIN(i,j) >= k; k++){
            if ( i==k) l=1;
            else l=lu[i*matrix_dim+k];
            u=lu[k*matrix_dim+j];
            sum = sum + (l*u);
        }
        tmp[i*matrix_dim+j] = sum;
    }

  for (i=0; i<matrix_dim; i++){
      for (j=0; j<matrix_dim; j++){
          if ( fabs(m[i*matrix_dim+j]-tmp[i*matrix_dim+j]) > 0.0001)
            printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i*matrix_dim+j], tmp[i*matrix_dim+j]);
      }
  }
  free(tmp);
  return RET_SUCCESS;
}

