static func_ret_t create_matrix_local(float **mp, int size){
  float *m;
  int i,j;
  float lamda = -0.001;
  // Dynamic allocation for coe to avoid stack issues with large sizes, though original used array
  float *coe = (float*)malloc(sizeof(float)*(2*size-1));
  float coe_i =0.0;

  if (!coe) return RET_FAILURE;

  for (i=0; size > i; i++) {
      coe_i = 10*exp(lamda*i); 
      j=size-1+i;     
      coe[j]=coe_i;
      j=size-1-i;     
      coe[j]=coe_i;
  }

  m = (float*) malloc(sizeof(float)*size*size);
  if ( NULL == m) {
      free(coe);
      return RET_FAILURE;
  }

  for (i=0; size > i; i++) {
      for (j=0; size > j; j++) {
	m[i*size+j]=coe[size-1-i+j];
      }
  }

  free(coe);
  *mp = m;
  return RET_SUCCESS;
}

