static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {
  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

// Forward declaration of the CUDA implementation
extern void lud_cuda(float *m, int matrix_dim);

int main ( int argc, char *argv[] )
{
  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:n:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 'n':
      omp_num_threads = atoi(optarg);
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (1 == optind)) {
    fprintf(stderr, "Usage: %s [-v] [-n no. of threads] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  }
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }
  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  } 

  if (do_verify){
    printf("Before LUD\n");
    matrix_duplicate(m, &mm, matrix_dim);
  }

  stopwatch_start(&sw);
  lud_cuda(m, matrix_dim);
  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");
    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}

// CUDA Implementation of LUD
#define BS 16

__global__ void lud_diagonal_cuda(float* a, int size, int offset)
{
    int i, j, k;
    for (i = 0; i < BS; i++) {
        int row = offset + i;
        for (j = i; j < BS; j++) {
            int col = offset + j;
            float val = a[row * size + col];
            for (k = 0; k < i; k++) {
                val -= a[row * size + (offset + k)] * a[(offset + k) * size + col];
            }
            a[row * size + col] = val;
        }

        float temp = 1.0f / a[(offset + i) * size + (offset + i)];
        for (j = i + 1; j < BS; j++) {
            int col = offset + i;
            int row = offset + j;
            float val = a[row * size + col];
            for (k = 0; k < i; k++) {
                val -= a[row * size + (offset + k)] * a[(offset + k) * size + col];
            }
            a[row * size + col] = val * temp;
        }
    }
}

__global__ void lud_right_cuda(float* a, int size, int offset, int val_2)
{
    int item_1 = blockIdx.x;
    if (item_1 >= val_2) return;

    int i, j, k;
    float sum;           
    float temp[BS*BS];

    int base_row = offset;
    int target_col_start = offset + BS * (item_1 + 1);

    // Load temp
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp[i * BS + j] = a[size * (i + offset) + offset + j];
        }
    }

    // Process right block
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            sum = 0.0f;
            int col = target_col_start + j;
            int row = base_row + i;
            for (k = 0; k < i; k++) {
                sum += temp[BS * i + k] * a[(offset + k) * size + col];
            }
            a[row * size + col] -= sum;
        }
    }
}

__global__ void lud_bottom_cuda(float* a, int size, int offset, int val_2)
{
    int item_1 = blockIdx.x;
    if (item_1 >= val_2) return;

    int i, j, k;
    float sum;
    float temp[BS*BS];

    int base_col = offset;
    int target_row_start = offset + BS * (item_1 + 1);

    // Load temp (column of diagonal block)
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp[i * BS + j] = a[size * (i + offset) + offset + j];
        }
    }

    // Process bottom block
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum = 0.0f;
            int row = target_row_start + i;
            int col = base_col + j;
            for (k = 0; k < j; k++) {
                sum += a[row * size + (base_col + k)] * temp[BS * k + j];
            }
            float diag = a[size * (offset + j) + offset + j];
            a[row * size + col] = (a[row * size + col] - sum) / diag;
        }
    }
}

__global__ void lud_inter_cuda(float* a, int size, int offset, int val_2)
{
    int item_1 = blockIdx.x;
    int chunks_per_inter = val_2 * val_2;
    if (item_1 >= chunks_per_inter) return;

    int i, j, k;
    float item_0[BS];

    int v_8 = offset + BS * (1 + item_1 / val_2);
    int data_3 = offset + BS * (1 + item_1 % val_2);

    float temp_top[BS*BS];
    float tmp_9[BS*BS];

    // Load blocks
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp_top[i * BS + j]  = a[size * (i + offset) + j + data_3];
            tmp_9[i * BS + j] = a[size * (i + v_8) + offset + j];
        }
    }

    // Compute update
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) item_0[j] = 0.0f;

        for (k = 0; k < BS; k++) {
            float t9_val = tmp_9[BS * i + k];
            for (j = 0; j < BS; j++) {
                item_0[j] += t9_val * temp_top[BS * k + j];
            }
        }

        for (j = 0; j < BS; j++) {
            int row = i + v_8;
            int col = j + data_3;
            a[row * size + col] -= item_0[j];
        }
    }
}

void lud_cuda(float *a, int size)
{
    int offset;
    int val_2;
    int chunks_per_inter;

    float *d_a;
    size_t bytes = size * size * sizeof(float);
    cudaMalloc(&d_a, bytes);
    cudaMemcpy(d_a, a, bytes, cudaMemcpyHostToDevice);

    int bs = BS;

    for (offset = 0; size - bs > offset; offset += bs) {
        // Diagonal block
        lud_diagonal_cuda<<<1, 1>>>(d_a, size, offset);

        val_2 = (size - offset - bs) / bs;

        if (val_2 > 0) {
            // Right blocks
            lud_right_cuda<<<val_2, 1>>>(d_a, size, offset, val_2);

            // Bottom blocks
            lud_bottom_cuda<<<val_2, 1>>>(d_a, size, offset, val_2);

            // Inter blocks
            chunks_per_inter = val_2 * val_2;
            lud_inter_cuda<<<chunks_per_inter, 1>>>(d_a, size, offset, val_2);
        }
    }

    // Final diagonal
    lud_diagonal_cuda<<<1, 1>>>(d_a, size, offset);

    cudaMemcpy(a, d_a, bytes, cudaMemcpyDeviceToHost);
    cudaFree(d_a);
}
